export function SkillIcon({
  icon,
  className = "size-3.5 shrink-0",
}: {
  icon: SkillIconInput
  className?: string
}) {
  if (icon.source === "simple") {
    const simple = simpleIconRegistry[icon.name]
    if (!simple) return null
    return <SimpleIconGlyph icon={simple} className={className} />
  }

  if (icon.source === "huge") {
    const huge = hugeIconRegistry[icon.name as keyof typeof hugeIconRegistry]
    if (!huge) return null
    return (
      <HugeiconsIcon
        icon={huge}
        size={14}
        strokeWidth={2}
        className={className}
      />
    )
  }

  if (icon.source === "custom" && icon.name === "drizzle") {
    return <DrizzleIcon className={className} />
  }

  if (icon.source === "custom" && icon.name === "grpc") {
    return <GrpcIcon className={className} />
  }

  if (icon.source === "custom" && icon.name === "gorm") {
    return <GormIcon className={className} />
  }

  return null
}
